css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #08080c; color: #e5e5ea; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 24px 60px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.brand { font-size: 20px; font-weight: 900; letter-spacing: 0.1em; }
.brand span { color: #a855f7; }
.nav-links { display: flex; gap: 30px; }
.nav-links a { color: rgba(255,255,255,0.45); text-decoration: none; font-size: 13.5px; font-weight: 600; }
.nav-links a.active { color: white; }
.search-box input { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 999px; padding: 9px 18px; color: white; font-size: 13px; outline: none; width: 160px; }
.hero { padding: 70px 60px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.cat { display: inline-block; background: rgba(168,85,247,0.12); color: #c084fc; font-size: 11.5px; font-weight: 700; padding: 4px 12px; border-radius: 999px; margin-bottom: 18px; }
.hero h1 { font-size: 42px; font-weight: 800; line-height: 1.3; max-width: 680px; margin-bottom: 16px; }
.hero p { color: rgba(255,255,255,0.5); font-size: 15px; line-height: 1.8; max-width: 600px; margin-bottom: 22px; }
.meta { display: flex; align-items: center; gap: 10px; font-size: 13px; color: rgba(255,255,255,0.4); font-weight: 600; }
.avatar { width: 28px; height: 28px; border-radius: 50%; background: linear-gradient(135deg, #a855f7, #6366f1); display: flex; align-items: center; justify-content: center; color: white; font-size: 12px; font-weight: 700; }
.posts { padding: 10px 60px; }
.post-row { display: flex; gap: 30px; padding: 36px 0; border-bottom: 1px solid rgba(255,255,255,0.06); cursor: pointer; transition: 0.15s; }
.post-row:hover .post-content h2 { color: #c084fc; }
.post-row:last-child { border-bottom: none; }
.num { font-size: 36px; font-weight: 900; color: rgba(255,255,255,0.1); flex-shrink: 0; width: 60px; }
.post-content h2 { font-size: 24px; font-weight: 700; margin: 8px 0 8px; transition: 0.15s; }
.post-content p { color: rgba(255,255,255,0.45); font-size: 14px; line-height: 1.7; margin-bottom: 10px; max-width: 600px; }
.tags { display: flex; gap: 10px; padding: 40px 60px 70px; flex-wrap: wrap; }
.tag { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); color: rgba(255,255,255,0.5); padding: 7px 16px; border-radius: 999px; font-size: 12.5px; font-weight: 600; }
@media (max-width: 900px) { .navbar, .hero, .posts, .tags { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 30px; } .post-row { gap: 16px; } .num { font-size: 26px; width: 40px; } .post-content h2 { font-size: 19px; } }

